from flask import Flask, request
from functools import wraps
import requests


def require_oauth(func):
    @wraps(func)
    def decorated(*args, **kwargs):
        authorization = request.headers.get('Authorization')

        if not authorization:
            return {
                'status': 401,
                'error': 'Not Authorized'
            }

        else:
            split_auth = authorization.split(' ')

            # Check format is OAuth 2.0
            try:
                if len(split_auth) == 2 and \
                    split_auth[0] == "Bearer":

                    token = requests.post("http://token.api/token",
                                          params={'access_code': split_auth[-1]})
                    print(split_auth[-1])

                else:
                    return {
                        'status': 403,
                        'error': 'Not a valid format'
                }

            except:
                raise Exception('Server Error')

            return func(*args, **kwargs)

    return decorated


